import{i as e,r as t,s as n,t as r}from"./app-CtsYpi6G.js";var i=JSON.parse(`{"path":"/setup-and-deployment/TROUBLESHOOTING.html","title":"Server Troubleshooting Guide","lang":"en-US","frontmatter":{},"git":{},"filePathRelative":"setup-and-deployment/TROUBLESHOOTING.md"}`),a={name:`TROUBLESHOOTING.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="server-troubleshooting-guide" tabindex="-1"><a class="header-anchor" href="#server-troubleshooting-guide"><span>Server Troubleshooting Guide</span></a></h1><p>If your website doesn&#39;t load after a fresh installation, run through these diagnostic steps in order. Run all commands on your server as <code>root</code> (or prefix with <code>sudo</code>).</p><h2 id="_1-check-nginx-status-and-logs" tabindex="-1"><a class="header-anchor" href="#_1-check-nginx-status-and-logs"><span>1. Check Nginx Status and Logs</span></a></h2><p>First, see if the web server (Nginx) is running:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> systemctl status nginx</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>If it is running, check the Nginx error logs to see why the page isn&#39;t loading:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> <span class="token function">tail</span> <span class="token parameter variable">-n</span> <span class="token number">50</span> /var/log/nginx/error.log</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><strong>&quot;Connection refused&quot;</strong>: Nginx can&#39;t communicate with the backend (Gunicorn). (Go to Step 2)</li><li><strong>&quot;Permission denied&quot;</strong>: Nginx can&#39;t read the socket or files. (Go to Step 3)</li></ul><h2 id="_2-check-the-gunicorn-service-epsteintool" tabindex="-1"><a class="header-anchor" href="#_2-check-the-gunicorn-service-epsteintool"><span>2. Check the Gunicorn Service (epsteintool)</span></a></h2><p>See if the backend Django app is successfully running:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> systemctl status epsteintool</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>If it has an error or is failing repeatedly, check the exact error message from Python/Gunicorn:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> journalctl <span class="token parameter variable">-u</span> epsteintool <span class="token parameter variable">-n</span> <span class="token number">50</span> --no-pager</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Common errors in the journal:</p><ul><li><strong><code>ModuleNotFoundError: No module named ...</code></strong>: The virtual environment (<code>venv</code>) wasn&#39;t created properly or PIP dependencies failed to install.</li><li><strong><code>OperationalError: no such table</code></strong>: Database migrations haven&#39;t run. <code>cd /var/www/epsteintool &amp;&amp; source venv/bin/activate &amp;&amp; python3 manage.py migrate</code></li><li><strong><code>ImportError</code></strong> or WSGI errors: There is a bug in the code or a misconfiguration in <code>wsgi.py</code>.</li></ul><h2 id="_3-verify-the-socket-file" tabindex="-1"><a class="header-anchor" href="#_3-verify-the-socket-file"><span>3. Verify the Socket File</span></a></h2><p>If both Nginx and Gunicorn show as active, verify the communication bridge (the <code>.sock</code> file):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">ls</span> <span class="token parameter variable">-l</span> /var/www/epsteintool/epsteintool.sock</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><strong>If it does NOT exist</strong>: Gunicorn is failing to start and create it, or doesn&#39;t have permissions to write to <code>/var/www/epsteintool</code>.</li><li><strong>If it is owned by <code>root</code></strong>: Nginx (<code>www-data</code>) cannot read it.</li></ul><p><strong>To automatically fix permissions and the socket:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> <span class="token function">chown</span> <span class="token parameter variable">-R</span> www-data:www-data /var/www/epsteintool</span>
<span class="line"><span class="token function">sudo</span> systemctl daemon-reload</span>
<span class="line"><span class="token function">sudo</span> systemctl restart epsteintool</span>
<span class="line"><span class="token function">sudo</span> systemctl restart nginx</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_4-verify-static-files" tabindex="-1"><a class="header-anchor" href="#_4-verify-static-files"><span>4. Verify Static Files</span></a></h2><p>If the page loads without CSS/styling, Django hasn&#39;t collected static files or Nginx isn&#39;t serving them. Ensure you ran:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token builtin class-name">cd</span> /var/www/epsteintool</span>
<span class="line"><span class="token builtin class-name">source</span> venv/bin/activate</span>
<span class="line">python3 manage.py collectstatic <span class="token parameter variable">--noinput</span></span>
<span class="line"><span class="token function">sudo</span> <span class="token function">chown</span> <span class="token parameter variable">-R</span> www-data:www-data static/</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_5-check-the-firewall-ufw" tabindex="-1"><a class="header-anchor" href="#_5-check-the-firewall-ufw"><span>5. Check the Firewall (UFW)</span></a></h2><p>Make sure your server is actually allowing web traffic to reach Nginx:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> ufw status</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>If it says active, ensure HTTP and HTTPS are allowed:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> ufw allow <span class="token string">&#39;Nginx Full&#39;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>The <code>?v=2</code> cache-buster worked locally, but production still serves the old JS file. This means the Django web server (Nginx/WhiteNoise/Apache) hasn&#39;t picked up the modified static files yet because <code>collectstatic</code> hasn&#39;t been run or the server hasn&#39;t been restarted.</p><p>Ran command: <code>Wait-Event -Timeout 1</code></p><h2 id="_6-working-on-windows-your-local-dev-machine-but-not-on-the-linux-web-server" tabindex="-1"><a class="header-anchor" href="#_6-working-on-windows-your-local-dev-machine-but-not-on-the-linux-web-server"><span>6. Working on Windows (your local dev machine) but not on the Linux web server</span></a></h2><p>Django needs to collect and serve the updated static files in production.</p><p>On your production server, you need to:</p><ol><li>Pull the latest code changes.</li><li>Run Django&#39;s collectstatic command so Nginx/WhiteNoise picks up the modified JS: <code>python manage.py collectstatic --noinput</code></li><li>Restart gunicorn/your web server: <code>sudo systemctl restart gunicorn</code> (or whatever your service is named)</li></ol><h2 id="quick-diagnostic-command" tabindex="-1"><a class="header-anchor" href="#quick-diagnostic-command"><span>Quick Diagnostic Command</span></a></h2><p>Paste this command to get a quick overview of all the moving parts:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;--- NGINX ---&quot;</span> <span class="token operator">&amp;&amp;</span> systemctl is-active nginx <span class="token operator">&amp;&amp;</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;--- GUNICORN ---&quot;</span> <span class="token operator">&amp;&amp;</span> systemctl is-active epsteintool <span class="token operator">&amp;&amp;</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;--- SOCKET ---&quot;</span> <span class="token operator">&amp;&amp;</span> <span class="token function">ls</span> <span class="token parameter variable">-l</span> /var/www/epsteintool/epsteintool.sock</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,38)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};